import React, { useState } from "react";

/* ------------------------------------------------------------------ */
/* Styles                                                               */
/* ------------------------------------------------------------------ */

const styles = `

.documents-card{
  background:#ffffff;
  border-radius:16px;
  box-shadow:0 10px 30px rgba(30,40,90,0.08);
  overflow:hidden;
  border:1px solid #eef0f5;
}
.documents-topbar{
  height:6px;
  width:100%;
  background:linear-gradient(90deg,#f59f00,#f06595);
}
.documents-body{
  padding:28px 32px 32px;
}
.documents-header{
  display:flex;
  align-items:center;
  gap:14px;
  margin-bottom:26px;
}
.documents-icon{
  width:46px;
  height:46px;
  border-radius:12px;
  background:linear-gradient(135deg,var(--grad-start),var(--grad-end));
  display:flex;
  align-items:center;
  justify-content:center;
  color:#fff;
  font-size:20px;
  flex-shrink:0;
}
.documents-header h5{
  margin:0;
  font-weight:700;
  color:#20232a;
  font-size:1.15rem;
}
.documents-header small{
  color:#8a8f98;
  font-size:0.82rem;
}
.documents-grid{
  display:grid;
  grid-template-columns:1fr 1fr 1fr;
  gap:20px;
  margin-bottom:20px;
}
@media (max-width: 800px){
  .documents-grid{ grid-template-columns:1fr; }
  .documents-body{ padding:20px; }
}
.doc-column{
  background:#f6f7fb;
  border-radius:12px;
  padding:18px 18px 20px;
}
.doc-column-title{
  font-size:0.78rem;
  font-weight:700;
  letter-spacing:0.05em;
  color:#4b4f5a;
  margin-bottom:14px;
}
.doc-option{
  display:flex;
  align-items:center;
  gap:10px;
  padding:8px 0;
  cursor:pointer;
  user-select:none;
}
.doc-checkbox{
  width:20px;
  height:20px;
  border-radius:6px;
  flex-shrink:0;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:12px;
  color:#fff;
  border:1.5px solid #d3d6e0;
  background:#fff;
}
.doc-checkbox.checked{
  background:var(--purple);
  border-color:var(--purple);
}
.doc-option-label{
  font-size:0.9rem;
  color:#22242c;
  font-weight:500;
}
.selected-bar{
  display:flex;
  align-items:center;
  gap:10px;
  flex-wrap:wrap;
  background:#fff9ea;
  border:1px solid #ffe8a3;
  border-radius:10px;
  padding:14px 18px;
}
.selected-label{
  font-size:0.86rem;
  color:#9296a1;
  font-weight:600;
}
.selected-tag{
  background:var(--selected-bg);
  border:1px solid var(--selected-border);
  color:var(--selected-text);
  font-size:0.82rem;
  font-weight:600;
  border-radius:999px;
  padding:5px 14px;
}
`;

/* ------------------------------------------------------------------ */
/* Sub-components                                                       */
/* ------------------------------------------------------------------ */

function DocColumn({ title, options, selected, onToggle }) {
  return (
    <div className="doc-column">
      <div className="doc-column-title">{title}</div>
      {options.map((opt) => {
        const checked = selected.includes(opt);
        return (
          <div key={opt} className="doc-option" onClick={() => onToggle(opt)}>
            <span className={`doc-checkbox ${checked ? "checked" : ""}`}>{checked ? "✓" : ""}</span>
            <span className="doc-option-label">{opt}</span>
          </div>
        );
      })}
    </div>
  );
}

/* ------------------------------------------------------------------ */
/* Main component                                                       */
/* ------------------------------------------------------------------ */

const ID_PROOF_OPTIONS = ["Aadhar", "Driving License", "Passport"];
const ADDRESS_PROOF_OPTIONS = ["Voter ID", "Aadhar", "Utility Bill"];
const OTHER_PROOF_OPTIONS = ["Bank Passbook", "Electricity Bill", "Income Certificate"];

export default function DocumentsRequired() {
  const [idProof, setIdProof] = useState(["Aadhar"]);
  const [addressProof, setAddressProof] = useState(["Voter ID", "Aadhar"]);
  const [otherProof, setOtherProof] = useState(["Bank Passbook"]);

  const toggle = (list, setList, value) => {
    setList(list.includes(value) ? list.filter((v) => v !== value) : [...list, value]);
  };

  const allSelected = [...idProof, ...addressProof, ...otherProof];

  return (
    <div className="documents-wrapper">
      <style>{styles}</style>

      <div className="documents-card">
        <div className="documents-topbar"></div>
        <div className="documents-body">
          <div className="documents-header">
            <div className="documents-icon">📄</div>
            <div>
              <h5>Documents Required</h5>
              <small>What applicants must upload</small>
            </div>
          </div>

          <div className="documents-grid">
            <DocColumn
              title="ID PROOF"
              options={ID_PROOF_OPTIONS}
              selected={idProof}
              onToggle={(v) => toggle(idProof, setIdProof, v)}
            />
            <DocColumn
              title="ADDRESS PROOF"
              options={ADDRESS_PROOF_OPTIONS}
              selected={addressProof}
              onToggle={(v) => toggle(addressProof, setAddressProof, v)}
            />
            <DocColumn
              title="OTHER PROOF"
              options={OTHER_PROOF_OPTIONS}
              selected={otherProof}
              onToggle={(v) => toggle(otherProof, setOtherProof, v)}
            />
          </div>

          <div className="selected-bar">
            <span className="selected-label">Selected:</span>
            {allSelected.length === 0 ? (
              <span className="selected-label">None</span>
            ) : (
              allSelected.map((item, i) => (
                <span key={`${item}-${i}`} className="selected-tag">
                  {item}
                </span>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
